WITH f_group AS (
    SELECT device_id FROM gender_age WHERE `group` = 'F27-28'
),
 event_day AS (
    SELECT DISTINCT device_id FROM events WHERE SUBSTR(`timestamp`,1,10) = '2016-05-03'
 )
SELECT COUNT(*) * 1.0 / (SELECT COUNT(*) FROM f_group) AS percentage_f27_28_event
FROM f_group
WHERE device_id IN (SELECT device_id FROM event_day);

SQL:
WITH pembroke AS (
  SELECT `patient` FROM `patients` WHERE `birthplace` = 'Pembroke MA US'
),
grass AS (
  SELECT DISTINCT `PATIENT` FROM `allergies` WHERE `DESCRIPTION` = 'Allergy to grass pollen'
)
SELECT 100.0 * (SELECT COUNT(*) FROM pembroke p JOIN grass g ON p.patient = g.PATIENT)
       / (SELECT COUNT(*) FROM pembroke) AS percentage;

